  private String queryInternalForLink(String prefix, String suffix) {

    import sailpoint.object.Filter;
    import sailpoint.object.Identity;
    import sailpoint.object.QueryOptions;

    QueryOptions ops = new QueryOptions();

    ops.addFilter(Filter.eq("links.displayName", prefix + "@" + suffix));

    List internalLinks = context.getObjects(Identity.class, ops);

    if (internalLinks != null && internalLinks.size() > 0) {

      userCheck = "Found";

    } else {

      userCheck = "NotFound";

    }

    internalLinks.clear();

    return userCheck;

  }

  private String queryGSuiteForUser(String prefix, String suffix) {

    try {

      token = context.decrypt(jobj); //Passed in via global variable (Rule-GSuite-AccessToken).

      String urlStr = "https://www.googleapis.com/admin/directory/v1/users/" + prefix + "@" + suffix;

      URL url = new URL(urlStr);

      HttpURLConnection conn = (HttpURLConnection) url.openConnection();
      conn.setDoOutput(true);
      conn.setRequestMethod("GET");
      conn.setRequestProperty("Content-Type", "application/json");
      conn.setRequestProperty("Authorization", "Bearer "+ token);

      BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()));
      String output = "";
      String lineOutput = "";

      while ((lineOutput = br.readLine()) != null) {
        output = output + lineOutput;
      } 
      br.close();
      if (output != null) {

        userCheck = "Found";

      }

    } catch (FileNotFoundException e) {

      userCheck = "NotFound";

    } catch (java.io.IOException e) {

      userCheck = "Forbidden";

    }     

    return userCheck;

  }
  
  static String psOutput; //psReader(String command) method sets this variable

  public void psReader(String command){

    import java.io.BufferedReader;
    import java.io.IOException;
    import java.io.InputStreamReader;

    try{

      java.lang.Process proc = Runtime.getRuntime().exec(command);

      proc.getOutputStream().close();

      String line;

      BufferedReader stdout = new BufferedReader(new InputStreamReader(proc.getInputStream()));

      while ((line = stdout.readLine()) != null) {

        psOutput = line;

      }

      stdout.close();

    } catch (Exception ex) {

      "Error:" + ex;

    }

  }

  private String queryARSForEmailAddressConflict(String prefix, String suffix){

    String command = "powershell.exe D:/IQScripts/Check-Email-ARS.ps1" + " " + prefix + "@" + suffix;

    psReader(command);

    return psOutput;

  }

  private String queryARSForProxyAddressConflict(String primaryEmail){

    //This method is intended for lookup AFTER the GSuite link exists

    String command = "powershell.exe D:/IQScripts/Check-ProxyAddress-ARS.ps1" + " " + primaryEmail;

    psReader(command);

    return psOutput;

  }

  private String queryARSForTargetAddressConflict(String primaryEmail){

    //This method is intended for lookup AFTER the GSuite link exists

    String command = "powershell.exe D:/IQScripts/Check-TargetAddress-ARS.ps1" + " " + primaryEmail;

    psReader(command);

    return psOutput;

  }
  
  private String queryCheckUpnArs(String primaryEmail){

    //This method is intended for lookup the Check-UPN-ARS 

    String command = "powershell.exe D:/IQScripts/Check-UPN-ARS.ps1" + " " + primaryEmail;

    psReader(command);

    return psOutput;

  }

  public static Boolean doUniqueCheck(String prefix, String suffix) {
    
    import sailpoint.tools.Util;

    Boolean isUnique = true;
    
    //Sequence is IdentityIQ, ARS, GSuite.
    //If any in sequence have an existing object matching the current iteration, the next iteration will begin.

    if (Util.nullSafeCaseInsensitiveEq(queryInternalForLink(prefix,suffix), "Found")) {

      isUnique = false;

    } else if (Util.nullSafeCaseInsensitiveEq(queryARSForEmailAddressConflict(prefix,suffix), "UniqueCheckFailed")) {

      isUnique = false;

    } else if (Util.nullSafeCaseInsensitiveEq(queryGSuiteForUser(prefix,suffix), "Found")) {

      isUnique = false;

    }

    return isUnique;

  }

  public static String queryUntilUnique(String prefix, String suffix) {

    int attempt = 0;

    Boolean isUnique = doUniqueCheck(prefix, suffix);

    if (isUnique == false) {

      do {

        attempt++;

        newPrefix = prefix + attempt;

        isUnique = doUniqueCheck(newPrefix, suffix);

      } while (!isUnique == true);

        return newPrefix + "@" + suffix;

    } else {

      return prefix + "@" + suffix;

    }

  }
